var labelsList = "\n";
var valid = true;

jQuery('.field-error').each(function() {
if (!jQuery(this).is(':empty')){
var parent = jQuery(this).parent();
var label = parent[0].firstChild.data;

if (label !== undefined) {
labelsList += label + "\n";
}
valid = false;
}
});

if (!valid) {
alert("La sauvegarde a échoué à cause d'une erreur dans la fiche, veuillez corriger les champs avec erreur" +
labelsList);
}
return valid;

});



